module top_module( input [7:0] minutes,
                    output reg am_pm,
                    output reg [7:0]twelve_hour_out
    );always@(*)
begin
if (minutes > 12) 
    begin
    am_pm <= 1;
    twelve_hour_out <= minutes - 12;
    end
if (minutes == 12) 
    begin
    am_pm <= 1;
    twelve_hour_out <= minutes;
    end    
if ((minutes < 12) && (minutes > 0)) 
    begin
    am_pm <= 0;
    twelve_hour_out <= minutes;
    end
if (minutes == 0) 
    begin
    am_pm <= 0;
    twelve_hour_out <= 12;
    end    
end


endmodule
